@code {
    private List<Channel>? _channels;
    private List<Message>? _messages;
    private List<Message>? _allChannelMessages; // includes replies, for counting
    private Channel? _activeChannel;
    private int _activeChannelId;

    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;

    private string _newMessage = "";
    private string _newThreadReply = "";

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private bool _loadingMore;
    private int _skip;
    private const int PageSize = 20;

    private ElementReference _messageListRef;

    private readonly string[] _quickEmojis = { "👍", "❤️", "😂", "🎉", "👀", "🚀" };

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
            await SelectChannelAsync(_channels[0].Id);
    }

    private async Task SelectChannelAsync(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels?.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        // Fetch a broader set for reply counting
        _allChannelMessages = _messages;

        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();

        CloseThread();
    }

    private async Task OnMessageScroll()
    {
        // This event fires on any scroll; actual scroll-to-top detection
        // would require JS interop. We provide a manual "Load more" as fallback.
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingMore) return;
        _loadingMore = true;
        _skip += PageSize;

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _skip, PageSize);
        if (older.Count > 0 && _messages is not null)
        {
            _messages.InsertRange(0, older);
        }
        _loadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage)) return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId, _newMessage.Trim(), null);
        _messages?.Add(msg);
        _newMessage = "";
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
            await SendMessageAsync();
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadRootMessage = _threadMessages?.FirstOrDefault();
        _threadOpen = true;
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadMessages = null;
        _threadRootMessage = null;
        _newThreadReply = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_newThreadReply) || _threadRootId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId, _newThreadReply.Trim(), _threadRootId);
        _threadMessages?.Add(reply);
        _newThreadReply = "";
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
            await SendThreadReplyAsync();
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        _messages = await ChatService.GetMessagesAsync(_activeChannelId, 0, _skip + PageSize);

        // Refresh thread if open
        if (_threadOpen && _threadRootId is not null)
            _threadMessages = await ChatService.GetThreadAsync(_threadRootId.Value);
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private int GetReplyCount(int messageId)
    {
        // Count from thread service (simplified: count from all known messages)
        return _allChannelMessages?.Count(m => m.ReplyToId == messageId) ?? 0;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";
}

