@page "/chat"
@using sv_d29e790e11a548ccae3d7829d0fd3dbc.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar ── *@
    <aside class="channel-sidebar">
        <h4 class="sidebar-title">Channels</h4>
        @if (_channels is not null)
        {
            @foreach (var ch in _channels)
            {
                <button class="channel-item @(ch.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch.Id)">
                    <span class="channel-name"># @ch.Name</span>
                    <span class="channel-desc">@Truncate(ch.Description, 28)</span>
                    @if (ch.UnreadCount > 0)
                    {
                        <span class="unread-badge">@ch.UnreadCount</span>
                    }
                </button>
            }
        }
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(_threadOpen ? "" : "full-width")">
        @if (_activeChannel is not null)
        {
            <header class="channel-header">
                <h5># @_activeChannel.Name</h5>
                <span class="channel-header-desc">@_activeChannel.Description</span>
            </header>
        }

        <div class="message-list" @onscroll="OnMessageScroll" @ref="_messageListRef">
            @if (_loadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @if (_messages is not null)
            {
                @foreach (var msg in _messages)
                {
                    <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                         @onmouseleave="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                        <div class="message-bubble">
                            <div class="message-meta">
                                <strong class="msg-author">@msg.Author</strong>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <p class="msg-content">@msg.Content</p>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var replyCount = GetReplyCount(msg.Id); }
                            @if (replyCount > 0)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    💬 @replyCount @(replyCount == 1 ? "reply" : "replies")
                                </button>
                            }
                        </div>

                        @if (_hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread" @onclick="() => OpenThreadAsync(msg.Id)">💬 Reply</button>
                                <div class="emoji-picker-wrapper">
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                    @if (_emojiPickerMessageId == msg.Id)
                                    {
                                        <div class="emoji-picker">
                                            @foreach (var emoji in _quickEmojis)
                                            {
                                                <button class="emoji-option"
                                                        @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                            }
                                        </div>
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            }
        </div>

        <div class="message-input-area">
            <textarea class="msg-input" rows="2" placeholder="Type a message…"
                      @bind="_newMessage" @bind:event="oninput"
                      @onkeydown="OnMessageKeyDown" />
            <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_newMessage)"
                    @onclick="SendMessageAsync">Send</button>
        </div>
    </section>

    @* ── Right Thread Panel ── *@
    @if (_threadOpen)
    {
        <aside class="thread-panel">
            <header class="thread-header">
                <h5>Thread</h5>
                <button class="close-btn" @onclick="CloseThread">✕</button>
            </header>

            @if (_threadRootMessage is not null)
            {
                <div class="thread-root-quote">
                    <strong>@_threadRootMessage.Author</strong>
                    <span class="msg-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                    <p>@_threadRootMessage.Content</p>
                </div>
            }

            <div class="thread-messages">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages.Skip(1))
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-meta">
                                <strong class="msg-author">@reply.Author</strong>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <p class="msg-content">@reply.Content</p>
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="msg-input" rows="2" placeholder="Reply in thread…"
                          @bind="_newThreadReply" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_newThreadReply)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

